mapper.select:
SELECT c.id, c.challenge_id as challengeId, c.user_id as userId, u.username, c.mode, c.question_set_id as questionSetId, c.time_limit as timeLimit, c.time_used as timeUsed, c.score, c.completed_count as completedCount, c.total_count as totalCount, c.status, c.create_time as createTime, c.finish_time as finishTime FROM x_challenge c LEFT JOIN x_user u ON c.user_id = u.id
AND c.user_id = #{userId}
AND c.mode = #{mode}
AND c.status = #{status}
ORDER BY c.create_time DESC
